'use client'

import { useState, useEffect } from 'react'
import { supabase } from '../../../lib/supabase'
import { Notification } from '../../../types'
import { Header } from '../../../components/layout/Header'
import { NotificationList } from '../../../components/notifications/NotificationList'
import { NotificationStats } from '../../../components/notifications/NotificationStats'
import { SearchBar } from '../../../components/common/SearchBar'
import { Pagination } from '../../../components/common/Pagination'
import { toast } from 'react-hot-toast'
import { FiPlus, FiBell, FiFilter, FiCalendar } from 'react-icons/fi'
import Link from 'next/link'

export default function NotificationsPage() {
  const [notifications, setNotifications] = useState<Notification[]>([])
  const [loading, setLoading] = useState(true)
  const [search, setSearch] = useState('')
  const [page, setPage] = useState(1)
  const [totalPages, setTotalPages] = useState(1)
  const [filter, setFilter] = useState('all')
  const [dateRange, setDateRange] = useState('all')
  const itemsPerPage = 10

  useEffect(() => {
    fetchNotifications()
    setupRealtimeSubscription()
  }, [page, search, filter, dateRange])

  const fetchNotifications = async () => {
    try {
      setLoading(true)
      
      let query = supabase
        .from('notifications')
        .select('*', { count: 'exact' })

      if (search) {
        query = query.or(`title.ilike.%${search}%,message.ilike.%${search}%`)
      }

      if (filter !== 'all') {
        query = query.eq('type', filter)
      }

      if (dateRange !== 'all') {
        const now = new Date()
        let startDate = new Date()
        
        switch (dateRange) {
          case 'today':
            startDate.setHours(0, 0, 0, 0)
            break
          case 'week':
            startDate.setDate(now.getDate() - 7)
            break
          case 'month':
            startDate.setMonth(now.getMonth() - 1)
            break
        }
        
        query = query.gte('created_at', startDate.toISOString())
      }

      const from = (page - 1) * itemsPerPage
      const to = from + itemsPerPage - 1

      const { data, error, count } = await query
        .range(from, to)
        .order('created_at', { ascending: false })

      if (error) throw error

      setNotifications(data || [])
      setTotalPages(Math.ceil((count || 0) / itemsPerPage))
    } catch (error) {
      toast.error('Failed to load notifications')
    } finally {
      setLoading(false)
    }
  }

  const setupRealtimeSubscription = () => {
    const subscription = supabase
      .channel('notifications-realtime')
      .on('postgres_changes', 
        { event: '*', schema: 'public', table: 'notifications' },
        fetchNotifications
      )
      .subscribe()

    return () => subscription.unsubscribe()
  }

  const handleDeleteNotification = async (notificationId: string) => {
    if (!confirm('Are you sure you want to delete this notification?')) return
    
    try {
      const { error } = await supabase
        .from('notifications')
        .delete()
        .eq('id', notificationId)

      if (error) throw error
      
      toast.success('Notification deleted successfully')
    } catch (error) {
      toast.error('Failed to delete notification')
    }
  }

  const handleResendNotification = async (notificationId: string) => {
    try {
      const { data: notification } = await supabase
        .from('notifications')
        .select('*')
        .eq('id', notificationId)
        .single()

      if (!notification) throw new Error('Notification not found')

      // Re-process notification logic
      toast.success('Notification resent successfully')
    } catch (error) {
      toast.error('Failed to resend notification')
    }
  }

  const getStats = () => {
    const total = notifications.length
    const banner = notifications.filter(n => n.type === 'banner').length
    const fullscreen = notifications.filter(n => n.type === 'fullscreen').length
    const totalSent = notifications.reduce((sum, n) => sum + n.sent_count, 0)
    const totalRead = notifications.reduce((sum, n) => sum + n.read_count, 0)
    const readRate = totalSent > 0 ? (totalRead / totalSent) * 100 : 0

    return { total, banner, fullscreen, totalSent, totalRead, readRate }
  }

  const stats = getStats()

  return (
    <div className="space-y-6">
      <Header 
        title="Notifications Management" 
        subtitle="Create, manage, and track notifications sent to users"
      />

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        <div className="lg:col-span-3 space-y-6">
          <div className="bg-white rounded-lg shadow p-6">
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center space-x-4">
                <SearchBar 
                  value={search}
                  onChange={setSearch}
                  placeholder="Search notifications..."
                />
                
                <select
                  value={filter}
                  onChange={(e) => setFilter(e.target.value)}
                  className="px-4 py-2 border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary"
                >
                  <option value="all">All Types</option>
                  <option value="banner">Banner</option>
                  <option value="fullscreen">Full Screen</option>
                </select>
                
                <select
                  value={dateRange}
                  onChange={(e) => setDateRange(e.target.value)}
                  className="px-4 py-2 border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary"
                >
                  <option value="all">All Time</option>
                  <option value="today">Today</option>
                  <option value="week">Last 7 Days</option>
                  <option value="month">Last 30 Days</option>
                </select>
              </div>

              <Link
                href="/dashboard/notifications/create"
                className="flex items-center space-x-2 px-4 py-2 bg-primary text-white rounded-lg hover:bg-primary-dark"
              >
                <FiPlus />
                <span>Create Notification</span>
              </Link>
            </div>

            <NotificationList 
              notifications={notifications}
              loading={loading}
              onDelete={handleDeleteNotification}
              onResend={handleResendNotification}
            />

            <Pagination 
              currentPage={page}
              totalPages={totalPages}
              onPageChange={setPage}
            />
          </div>

          <div className="bg-white rounded-lg shadow p-6">
            <h3 className="text-lg font-semibold text-text mb-4">Notification Performance</h3>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              <div className="p-4 bg-blue-50 rounded-lg">
                <p className="text-sm text-text-light">Total Sent</p>
                <p className="text-2xl font-bold text-text">{stats.totalSent}</p>
              </div>
              <div className="p-4 bg-green-50 rounded-lg">
                <p className="text-sm text-text-light">Total Read</p>
                <p className="text-2xl font-bold text-success">{stats.totalRead}</p>
              </div>
              <div className="p-4 bg-purple-50 rounded-lg">
                <p className="text-sm text-text-light">Read Rate</p>
                <p className="text-2xl font-bold text-primary">{stats.readRate.toFixed(1)}%</p>
              </div>
              <div className="p-4 bg-yellow-50 rounded-lg">
                <p className="text-sm text-text-light">Avg. Response Time</p>
                <p className="text-2xl font-bold text-text">2.4h</p>
              </div>
            </div>
          </div>
        </div>

        <div className="space-y-6">
          <NotificationStats stats={stats} />
          
          <div className="bg-white p-6 rounded-lg shadow">
            <h3 className="text-lg font-semibold text-text mb-4">Quick Actions</h3>
            <div className="space-y-3">
              <button className="w-full px-4 py-3 border border-border rounded-lg hover:bg-gray-50 text-left">
                Schedule Notification
              </button>
              <button className="w-full px-4 py-3 border border-border rounded-lg hover:bg-gray-50 text-left">
                Create Template
              </button>
              <button className="w-full px-4 py-3 border border-border rounded-lg hover:bg-gray-50 text-left">
                View Analytics
              </button>
            </div>
          </div>

          <div className="bg-white p-6 rounded-lg shadow">
            <h3 className="text-lg font-semibold text-text mb-4">Notification Types</h3>
            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <div className="flex items-center space-x-3">
                  <div className="w-8 h-8 bg-blue-100 rounded-lg flex items-center justify-center">
                    <FiBell className="text-blue-600" />
                  </div>
                  <span>Banner</span>
                </div>
                <span className="font-medium">{stats.banner}</span>
              </div>
              <div className="flex items-center justify-between">
                <div className="flex items-center space-x-3">
                  <div className="w-8 h-8 bg-purple-100 rounded-lg flex items-center justify-center">
                    <FiBell className="text-purple-600" />
                  </div>
                  <span>Full Screen</span>
                </div>
                <span className="font-medium">{stats.fullscreen}</span>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  )
}